div.style:
background:rgba(231,76,45,0.08);
                border:1px solid rgba(231,76,45,0.35);
                border-left:4px solid #E74C2D;
                border-radius:8px;
                padding:10px 16px;
                display:flex;align-items:center;gap:10px;
                font-size:13px;color:#b03520;

t.script:
(function(){
var f = document.getElementById('date_from');
var t = document.getElementById('date_to');
var d = document.getElementById('total_days_display');
var overlapRow = document.getElementById('overlap-warning-row');
var overlapText = document.getElementById('overlap-warning-text');
var submitBtn = document.querySelector('button[type="submit"].lv-submit-btn');
if(!f || !t || !d) return;


var existingLeaves = [];
try {
var raw = document.getElementById('lv-existing-leaves');
if(raw) existingLeaves = JSON.parse(raw.textContent || '[]');
} catch(e){ existingLeaves = []; }


function countWorkdays(from, to){
var count = 0;
var cur = new Date(from); cur.setHours(0,0,0,0);
var end = new Date(to); end.setHours(0,0,0,0);
while(cur <= end){
var w = cur.getDay();
if(w !== 0 && w !== 6) count++;
cur.setDate(cur.getDate() + 1);
}
return count;
}

function toStr(dt){
var y = dt.getFullYear();
var m = String(dt.getMonth()+1).padStart(2,'0');
var day = String(dt.getDate()).padStart(2,'0');
return y + '-' + m + '-' + day;
}

function snapToWorkday(input){
if(!input.value) return;
var dt = new Date(input.value + 'T00:00:00');
var w = dt.getDay();
if(w === 6){ dt.setDate(dt.getDate() + 2); input.value = toStr(dt); }
else if(w === 0){ dt.setDate(dt.getDate() + 1); input.value = toStr(dt); }
}

function nextWorkday(str){
var dt = new Date(str + 'T00:00:00');
var w = dt.getDay();
if(w === 6) dt.setDate(dt.getDate() + 2);
else if(w === 0) dt.setDate(dt.getDate() + 1);
return toStr(dt);
}


function checkOverlap(fromStr, toStr){
if(!fromStr || !toStr) return null;
var newFrom = new Date(fromStr + 'T00:00:00');
var newTo = new Date(toStr + 'T00:00:00');
for(var i = 0; i < existingLeaves.length; i++){
var lv = existingLeaves[i];
if(!lv.from || !lv.to) continue;
var exFrom = new Date(lv.from + 'T00:00:00');
var exTo = new Date(lv.to + 'T00:00:00');

if(newFrom <= exTo && newTo >= exFrom){
return lv;
}
}
return null;
}

function formatDate(str){
if(!str) return '';
var dt = new Date(str + 'T00:00:00');
var months = ['Jan','Feb','Mar','Apr','May','Jun',
'Jul','Aug','Sep','Oct','Nov','Dec'];
return dt.getDate() + ' ' + months[dt.getMonth()] + ' ' + dt.getFullYear();
}

function updateTotal(){
if(!f.value || !t.value){
d.textContent = '—'; d.style.color = '';
hideOverlap();
return;
}
var a = new Date(f.value + 'T00:00:00');
var b = new Date(t.value + 'T00:00:00');
if(a > b){
d.textContent = 'Invalid range'; d.style.color = '#c0392b';
hideOverlap();
return;
}
var n = countWorkdays(a, b);
d.textContent = n + ' Day' + (n !== 1 ? 's' : '');
d.style.color = '#1B2A4A';


var conflict = checkOverlap(f.value, t.value);
if(conflict){
showOverlap(
'These dates overlap with an existing leave request (' +
formatDate(conflict.from) + ' – ' + formatDate(conflict.to) +
'). Please choose different dates.'
);
} else {
hideOverlap();
}
}

function showOverlap(msg){
overlapText.textContent = msg;
overlapRow.style.display = 'block';
d.style.color = '#c0392b';

if(submitBtn){ submitBtn.disabled = true; submitBtn.style.opacity = '0.5'; }
}

function hideOverlap(){
overlapRow.style.display = 'none';

if(submitBtn){ submitBtn.disabled = false; submitBtn.style.opacity = '1'; }
}


f.addEventListener('change', function(){
snapToWorkday(f);
if(f.value){
t.setAttribute('min', f.value);
if(t.value && t.value < f.value){ t.value = f.value; snapToWorkday(t); }
}
updateTotal();
});


t.addEventListener('change', function(){ snapToWorkday(t); updateTotal(); });


var requireDocMap = {};
try {
var rdEl = document.getElementById('lv-require-doc-map');
if(rdEl){
var ta = document.createElement('textarea');
ta.innerHTML = rdEl.textContent || '{}';
requireDocMap = JSON.parse(ta.value || '{}');
}
} catch(e){ requireDocMap = {}; }
var typeSel = document.getElementById('leave_type_id');
var fileInput = document.getElementById('leave_attachment');
var reqStar = document.getElementById('lv-attach-required');
var optTag = document.getElementById('lv-attach-optional');
var hint = document.getElementById('lv-attach-hint');
function updateDocRequirement(){
var needed = typeSel && requireDocMap[typeSel.value] === true;
if(reqStar) reqStar.style.display = needed ? 'inline' : 'none';
if(optTag) optTag.style.display = needed ? 'none' : 'inline';
if(hint) hint.style.display = needed ? 'block' : 'none';
if(fileInput){
if(needed){ fileInput.setAttribute('required','required'); }
else { fileInput.removeAttribute('required'); }
}
}
if(typeSel){
typeSel.addEventListener('change', updateDocRequirement);
updateDocRequirement();
}

})();


(function() {
if (window.location.hash === '#leave-requests-section') {
var el = document.getElementById('leave-requests-section');
if (el) { setTimeout(function() { el.scrollIntoView({ behavior: 'smooth', block: 'start' }); }, 100); }
}
})();


(function(){
if (window.history && window.history.replaceState) {
var url = new URL(window.location.href);
var hadFlag = url.searchParams.has('success')
|| url.searchParams.has('error')
|| url.searchParams.has('error_msg');
if (hadFlag) {
url.searchParams.delete('success');
url.searchParams.delete('error');
url.searchParams.delete('error_msg');

window.history.replaceState({}, document.title,
url.pathname + url.search + url.hash);
}
}
})();
